import { BrowserRouter, Route, Routes } from 'react-router-dom';
import Layout from '../pages/layout';
import Home from '../pages/home';
import Panthers from '../pages/panthers';
import League from '../pages/league';
import Player from '../pages/player';
import TeamStats from '../pages/teamStats';
import Fixtures from '../pages/fixtures';


const AppRoutes = () => {

    return(
        <BrowserRouter>
            <Routes>
                <Route path="/" element={<Layout/>}>
                    <Route index element={<Home/>}></Route>     
                    <Route path="/fixtures/:id" element={<Fixtures/>}></Route>   
                    <Route path="/player" element={<Player/>}></Route>   
                    <Route path="/league" element={<League/>}></Route>   
                    <Route path="/panthers" element={<Panthers/>}></Route>   
                    <Route path="/stats" element={<TeamStats/>}></Route>   
                    <Route path="*" element={<Home/>}></Route>
                </Route>
            </Routes>
        </BrowserRouter>   
    )
}

export default AppRoutes;
